"use client";

import Umbra, { type Options } from "@emrocode/umbra";
import { createContext, type ReactNode, useContext, useState } from "react";
import { KeyboardShortcut } from "./plugins";

const options: Partial<Options> = {
  autoMatchTheme: true,
  useColorScheme: ["#ffffff", "#000000"],
  useStorage: "local",
  usePlugins: [KeyboardShortcut],
};

const umb = new Umbra(options);

const ThemeContext = createContext<{
  theme: string;
  toggleTheme: () => void;
} | null>(null);

export const ThemeProvider = ({ children }: { children: ReactNode }) => {
  const [theme, setTheme] = useState<string>(umb.getCurrentTheme());

  const toggleTheme = () => {
    umb.toggleTheme();
    setTheme(umb.getCurrentTheme());
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return context;
};

import type { Host, Plugin } from "@emrocode/umbra";

interface KeyboardShortcutOptions {
  key?: string;
  ctrl?: boolean;
  shift?: boolean;
  target?: "body" | "input" | "all";
  cooldown?: number;
}

export class KeyboardShortcut implements Plugin {
  public static readonly pluginId = "u-keyboard-shortcut";
  private _host: Host;
  private options: Required<KeyboardShortcutOptions>;
  private _lastTriggered: number = 0;

  constructor(host: Host, options?: KeyboardShortcutOptions) {
    this._host = host;
    this.options = {
      key: options?.key ?? "d",
      ctrl: options?.ctrl ?? false,
      shift: options?.shift ?? false,
      target: options?.target ?? "body",
      cooldown: options?.cooldown ?? 300,
    };
  }

  private handleKeyDown = (e: KeyboardEvent) => {
    if (this.options.target === "body" && this.isTyping(e)) return;
    if (this.options.target === "input" && !this.isTyping(e)) return;

    if (this.matches(e)) {
      e.preventDefault();

      const now = Date.now();
      if (now - this._lastTriggered < this.options.cooldown) return;

      this._lastTriggered = now;
      this._host.toggleTheme();
    }
  };

  render(): void {
    document.addEventListener("keydown", this.handleKeyDown);
  }

  onDestroy(): void {
    document.removeEventListener("keydown", this.handleKeyDown);
  }

  private matches(e: KeyboardEvent): boolean {
    return (
      e.key.toLowerCase() === this.options.key.toLowerCase() &&
      (!this.options.ctrl || e.ctrlKey || e.metaKey) &&
      (!this.options.shift || e.shiftKey) &&
      (this.options.ctrl || (!e.ctrlKey && !e.metaKey && !e.altKey))
    );
  }

  private isTyping(e: KeyboardEvent): boolean {
    const target = e.target as HTMLElement;
    const tagName = target.tagName.toLowerCase();
    const isEditable =
      target.isContentEditable || tagName === "input" || tagName === "textarea";
    return isEditable;
  }
}
